    @AiToolDef("Query furnace batches (炉次列表) on a given date within the current user's tenant/device scope")
    public ToolResult today_furnace_batches(
        @AiToolParam(
            name = "fnCode",
            value = "炉号编码（标准编码）。用户说“1号炉/炉号1/1#”时应解析为 fnCode=1。",
            required = true,
            aliasExamples = {"1号炉", "炉号1", "1#", "1号"},
            normalizationRule = "extract_furnace_code_number",
            clarifyTemplate = "请补充炉号编码（例如：1、2、3）。你也可以直接说“2号炉”。",
            acceptedExamples = {"1", "2", "3", "6"}
        ) String fnCode,
        @AiToolParam(
            name = "date",
            value = "目标日期，格式 YYYY-MM-DD；可选，不传默认今天。",
            normalizationRule = "relative_date_to_yyyy_mm_dd",
            aliasExamples = {"今天", "昨日", "昨天", "前天"},
            clarifyTemplate = "请补充日期（YYYY-MM-DD），例如：2026-03-05；不填默认今天。"
        ) String date,
        @AiToolParam(
            name = "limit",
            value = "最多返回条数，范围 1..500；常用 20/50/100。",
            clarifyTemplate = "请补充 limit（1~500 的整数），例如 50。"
        ) Integer limit,
        AiRunContext ctx
    ) {
        List<Long> didList = resolveVisibleDeviceIds(ctx);
        List<Long> deptIds = resolveVisibleDeptIds(ctx);
        if (didList.isEmpty() && deptIds.isEmpty()) {
            return ToolResult.fail("empty_scope", "上下文未包含可见设备/工厂范围，拒绝查询炉次数据");
        }
        if (fnCode == null || fnCode.trim().isEmpty()) {
            ObjectNode args = objectMapper.createObjectNode();
            args.putNull("fnCode");
            if (date != null) {
                args.put("date", date);
            } else {
                args.putNull("date");
            }
            if (limit != null) {
                args.put("limit", limit);
            } else {
                args.putNull("limit");
            }
            return missingArg("fnCode", args);
        }
        int capped = limit == null ? 100 : limit;
        if (capped <= 0 || capped > 500) {
            return ToolResult.fail("tool_args_invalid", "limit必须在1..500之间");
        }

        LocalDate targetDate;
        if (date == null || date.isBlank()) {
            targetDate = LocalDate.now();
        } else {
            try {
                targetDate = LocalDate.parse(date.trim());
            } catch (Exception e) {
                return ToolResult.fail("tool_args_invalid", "date格式错误(YYYY-MM-DD): " + date);
            }
        }

        List<TbDeviceFurnace> candidates = findFurnacesByFnCode(ctx, fnCode.trim());
        if (candidates.isEmpty()) {
            return ToolResult.fail("tool_exec_failed", "未找到匹配炉体，fnCode=" + fnCode.trim());
        }
        if (candidates.size() > 1) {
            ObjectNode data = objectMapper.createObjectNode();
            data.put("fnCode", fnCode.trim());
            data.put("candidateCount", candidates.size());
            ArrayNode candidateArr = objectMapper.createArrayNode();
            for (TbDeviceFurnace candidate : candidates) {
                ObjectNode item = objectMapper.createObjectNode();
                item.put("deviceInternalId", candidate.getDeviceInternalId());
                item.put("furnaceNo", candidate.getFnNo());
                item.put("furnaceCode", candidate.getFnCode());
                item.put("ownerDeptId", candidate.getOwnerDeptId());
                candidateArr.add(item);
            }
            data.set("candidates", candidateArr);
            return ToolResult.fail("tool_exec_failed", "fnCode匹配到多个炉体，请提供更精确条件", data);
        }

        TbDeviceFurnace targetFurnace = candidates.get(0);
        DeviceFurnaceReport report = castingFurnaceChargeBatchService.queryFurnaceReport(
            targetFurnace.getDeviceInternalId(),
            targetFurnace.getFnNo(),
            targetDate
        );

        List<QueryFurnaceReportVo> records = report == null || report.getRecordList() == null
            ? new ArrayList<>()
            : new ArrayList<>(report.getRecordList());
        records.sort((a, b) -> compareDesc(a == null ? null : a.getBatchStartedAt(), b == null ? null : b.getBatchStartedAt()));
        if (records.size() > capped) {
            records = records.subList(0, capped);
        }

        ArrayNode batchArr = objectMapper.createArrayNode();
        Map<String, Integer> abnormalityCounts = new LinkedHashMap<>();
        int abnormalBatchCount = 0;
        for (QueryFurnaceReportVo record : records) {
            if (record == null) {
                continue;
            }
            ObjectNode summaryNode = buildBatchSummaryNode(targetFurnace, targetDate, record);
            batchArr.add(summaryNode);
            if (summaryNode.path("abnormalityCount").asInt(0) > 0) {
                abnormalBatchCount++;
            }
            summaryNode.path("abnormalityTypes").forEach(type ->
                abnormalityCounts.merge(type.asText(), 1, Integer::sum)
            );
        }

        ArrayNode perFurnaceArr = objectMapper.createArrayNode();
        ObjectNode perFurnace = objectMapper.createObjectNode();
        perFurnace.put("deviceInternalId", targetFurnace.getDeviceInternalId());
        perFurnace.put("furnaceNo", targetFurnace.getFnNo());
        perFurnace.put("fnCode", targetFurnace.getFnCode());
        perFurnace.put("batchCount", batchArr.size());
        perFurnaceArr.add(perFurnace);

        ObjectNode data = objectMapper.createObjectNode();
        data.put("date", targetDate.toString());
        data.put("fnCode", targetFurnace.getFnCode());
        data.put("deviceInternalId", targetFurnace.getDeviceInternalId());
        data.put("furnaceNo", targetFurnace.getFnNo());
        data.put("limit", capped);
        data.put("batchCount", batchArr.size());
        data.put("abnormalBatchCount", abnormalBatchCount);
        data.put("totalPowerConsumption", report == null ? null : toPlainString(report.getTotalPowerConsumption()));
        data.put("tProductionCount", report == null ? null : report.getTProductionCount());
        data.set("perFurnaceCounts", perFurnaceArr);
        data.set("abnormalityCategorySummary", buildAbnormalityCategorySummary(abnormalityCounts));
        data.set("batches", batchArr);

        String preview = "date=" + targetDate
            + ", fnCode=" + targetFurnace.getFnCode()
            + ", did=" + targetFurnace.getDeviceInternalId()
            + ", fnNo=" + targetFurnace.getFnNo()
            + ", batches=" + batchArr.size()
            + ", abnormalBatches=" + abnormalBatchCount;
        return ToolResult.ok(preview, data);
    }

