    public TbFurnaceBatchAggregated findByChargeBatchId(Long chargeBatchId){
        var resultList = list(Wrappers.lambdaQuery(TbFurnaceBatchAggregated.class)
            .eq(TbFurnaceBatchAggregated::getChargeBatchId, chargeBatchId));
        if (resultList.size() > 1){
            log.error(String.format("Unexpected!: 一条加料炉次对应了多个综合炉次!! chargeBatchID = %s, 综合炉次: %s, 取第一个作为fallback",
