     * @param toleranceSeconds 时间容差(秒), 900 = 15分钟
     * @return 匹配的综合炉次列表
     */
    public List<TbFurnaceBatchAggregated> findByEndTimeRange(
        Long did, Integer fnNo, LocalDateTime endTime, Integer toleranceSeconds
    ) {
        LocalDateTime startRange = endTime.minusSeconds(toleranceSeconds);
        LocalDateTime endRange = endTime.plusSeconds(toleranceSeconds);

        return list(Wrappers.lambdaQuery(TbFurnaceBatchAggregated.class)
            .eq(TbFurnaceBatchAggregated::getDeviceInternalId, did)
            .eq(TbFurnaceBatchAggregated::getFurnaceNo, fnNo)
            .isNotNull(TbFurnaceBatchAggregated::getBatchEndedAt)
            .ge(TbFurnaceBatchAggregated::getBatchEndedAt, startRange)
            .le(TbFurnaceBatchAggregated::getBatchEndedAt, endRange)
        );
    }

