        // 如果shiftNo为null（所有班次），需要聚合同一炉体的多个班次数据
        Map<String, List<TbFurnaceBatchCostShiftAggregate>> furnaceDataMap = new HashMap<>();
        List<TbFurnaceBatchCostShiftAggregate> otherOutboundList = new ArrayList<>();

        if (allCosts != null) {
            for (TbFurnaceBatchCostShiftAggregate aggregate : allCosts) {
                Long deviceInternalId = aggregate.getDeviceInternalId();
                Integer furnaceNo = aggregate.getFurnaceNo();

                if (furnaceNo != null && deviceInternalId != null) {
                    String compositeKey = deviceInternalId + "_" + furnaceNo;
                    furnaceDataMap.computeIfAbsent(compositeKey, k -> new ArrayList<>()).add(aggregate);
                } else {
                    otherOutboundList.add(aggregate); // 记录"其他出库"数据
                }
            }
        }

        // 构建各炉体汇总列表（遍历所有炉体，补足缺失的炉体）
        List<CostBreakdownItem<ShiftlyFurnaceDimensionInfo>> furnaceSummaries = new ArrayList<>();

        for (TbDeviceFurnace furnace : allFurnaces) {
            Long deviceInternalId = furnace.getDeviceInternalId();
            Integer furnaceNo = furnace.getFnNo();

            // 使用复合键查询
            String compositeKey = deviceInternalId + "_" + furnaceNo;
            List<TbFurnaceBatchCostShiftAggregate> furnaceShifts = furnaceDataMap.get(compositeKey);

            CostBreakdownItem<ShiftlyFurnaceDimensionInfo> item;
            if (furnaceShifts != null && !furnaceShifts.isEmpty()) {
                // 聚合该炉体的所有班次数据
                item = createFurnaceBreakdownItemWithAggregatedShifts(furnace, furnaceShifts, shiftNo);
            } else {
                item = createEmptyFurnaceBreakdownItem(furnace);
            }

            furnaceSummaries.add(item);
        }

        // 处理"其他出库" (furnaceNo=null的聚合记录) - 添加到 furnaceSummaries 列表中
        if (!otherOutboundList.isEmpty()) {
            CostBreakdownItem<ShiftlyFurnaceDimensionInfo> item = new CostBreakdownItem<>();
            item.setDimensionType("shiftly_furnace");
            item.setDimensionId("other_outbound");
            item.setDimensionLabel("其他出库");
            item.setHasData(true);

            // 如果有多个班次的"其他出库"数据，需要聚合
            CostDetail aggregatedCost;
            if (otherOutboundList.size() == 1) {
                aggregatedCost = buildCostDetailFromAggregate(otherOutboundList.get(0));
            } else {
                aggregatedCost = aggregateShiftsCost(otherOutboundList);
            }
            item.setCostDetail(aggregatedCost);

            ShiftlyFurnaceDimensionInfo dimensionInfo = new ShiftlyFurnaceDimensionInfo();
            dimensionInfo.setFurnaceNo(null);
            dimensionInfo.setFurnaceLabel("其他出库");
            // 如果是所有班次，班次信息设为null
            if (shiftNo == null) {
                dimensionInfo.setShiftId(null);
                dimensionInfo.setShiftName(null);
            } else {
                // 单个班次，使用第一个记录的班次信息
                dimensionInfo.setShiftId(otherOutboundList.get(0).getShiftId());
                dimensionInfo.setShiftName(otherOutboundList.get(0).getShiftName());
            }
            dimensionInfo.setBatchCount(null); // 其他出库无炉次数量

            item.setDimensionInfo(dimensionInfo);
            furnaceSummaries.add(item);
        }

        response.setFurnaceSummaries(furnaceSummaries);

        log.info("查询所有炉体成本汇总完成: shiftNo={}, 列表数量={} (包含{}炉体+{}其他出库)",
            shiftNo, furnaceSummaries.size(), allFurnaces.size(),
            otherOutboundList.isEmpty() ? 0 : 1);

        return response;
    }

