    }

    private List<TbFurnaceBatchAggregated> queryAggregatedBatches(ExportFurnaceReq dto) {
        if (dto.getShiftId() != null) {
            TbCastingFurnaceOperatorShift shift = shiftMapper.selectById(dto.getShiftId());
            if (shift == null) {
                throw new ServiceException("班次不存在: shiftId=" + dto.getShiftId());
            }
            if (!Objects.equals(shift.getDeviceInternalId(), dto.getDeviceInternalId())) {
                throw new ServiceException(String.format(
                    "班次设备ID不匹配: 班次设备ID=%d, 请求设备ID=%d",
                    shift.getDeviceInternalId(), dto.getDeviceInternalId()
                ));
            }
            return tbFurnaceBatchAggregatedRepo.selectBatchListByShift(dto.getShiftId(), dto.getDeviceInternalId(), dto.getFurnaceNo());
        }
        return tbFurnaceBatchAggregatedRepo.selectBatchListByBatchDate(resolveReportDate(dto), dto.getDeviceInternalId(), dto.getFurnaceNo());
    }

    private Map<Long, TbCastingFurnaceChargeBatch> loadChargeBatchMap(List<TbFurnaceBatchAggregated> aggregatedBatches) {
        List<Long> chargeBatchIds = aggregatedBatches.stream()
            .map(TbFurnaceBatchAggregated::getChargeBatchId)
            .filter(Objects::nonNull)
            .distinct()
            .collect(Collectors.toList());
        if (chargeBatchIds.isEmpty()) {
            return Collections.emptyMap();
        }
        return tbCastingFurnaceChargeBatchMapper.selectList(Wrappers.lambdaQuery(TbCastingFurnaceChargeBatch.class)
                .in(TbCastingFurnaceChargeBatch::getId, chargeBatchIds))
            .stream()
            .collect(Collectors.toMap(TbCastingFurnaceChargeBatch::getId, Function.identity(), (left, right) -> left));
    }

    private String resolveFurnaceIdentifier(TbFurnaceBatchAggregated aggregatedBatch) {
        if (aggregatedBatch.getFactoryBatchCode() != null && !aggregatedBatch.getFactoryBatchCode().isBlank()) {
            return aggregatedBatch.getFactoryBatchCode();
        }
        return Optional.ofNullable(aggregatedBatch.getBatchNo()).map(String::valueOf).orElse("");
    }

    private String resolveFurnaceAge(TbFurnaceBatchAggregated aggregatedBatch, int furnaceAgeStart) {
        return Optional.ofNullable(aggregatedBatch.getFurnaceAge())
            .map(String::valueOf)
            .orElse(String.valueOf(furnaceAgeStart));
    }

    private Integer resolveLadleNumber(TbFurnaceBatchAggregated aggregatedBatch) {
        return Optional.ofNullable(aggregatedBatch.getLadleBatchCountActual())
            .orElse(Optional.ofNullable(aggregatedBatch.getLadleBatchCount()).orElse(DEFAULT_LADLE_NUMBER));
    }

    private Long resolveElapsedMinutes(TbFurnaceBatchAggregated aggregatedBatch) {
        if (aggregatedBatch.getElectricElapsedTime() != null) {
            return aggregatedBatch.getElectricElapsedTime();
        }
        return 0L;
    }

    private BigDecimal calculateTonPowerConsumption(BigDecimal powerConsumption, BigDecimal tappingWeight) {
        if (powerConsumption == null || tappingWeight == null || BigDecimal.ZERO.compareTo(tappingWeight) == 0) {
            return BigDecimal.ZERO;
        }
        return powerConsumption
            .multiply(BigDecimal.valueOf(1000))
            .divide(tappingWeight, 0, RoundingMode.HALF_UP);
    }

    private BigDecimal resolveTotalCharged(TbFurnaceBatchAggregated aggregatedBatch, TbCastingFurnaceChargeBatch chargeBatch) {
        if (chargeBatch != null) {
            BigDecimal totalCharged = chargeBatch.getFurnaceChargeRecordPreTappingList().stream()
                .map(TbCastingProductionBatch.FurnaceChargeRecord::getRecord)
                .filter(Objects::nonNull)
                .map(NameDecimalValueBo::getActual)
                .filter(Objects::nonNull)
                .reduce(BigDecimal.ZERO, BigDecimal::add);
            if (BigDecimal.ZERO.compareTo(totalCharged) != 0) {
                return totalCharged;
            }
        }
        return BigDecimal.ZERO;
    }

    private BigDecimal sumPower(List<FurnaceElectricInfo> electricInfos, Function<FurnaceElectricInfo, BigDecimal> extractor) {
        return electricInfos.stream()
            .map(extractor)
            .filter(Objects::nonNull)
            .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    private BigDecimal defaultZero(BigDecimal value) {
        return value == null ? BigDecimal.ZERO : value;
    }

    private Long defaultLong(Long value) {
        return value == null ? 0L : value;
    }

    private Long toEpochMilli(LocalDateTime value) {
        return value == null ? null : value.atZone(ZoneId.systemDefault()).toInstant().toEpochMilli();
    }

    private LocalDateTime firstNonNull(LocalDateTime primary, LocalDateTime fallback) {
        return primary != null ? primary : fallback;
    }


