    private final TbCastingFurnaceChargeBatchMapper tbCastingFurnaceChargeBatchMapper;
    private final TbCastingFurnaceOperatorShiftMapper tbCastingFurnaceOperatorShiftMapper;
    private final TbFurnaceBatchAggregatedMapper aggregatedBatchMapper;

    public void generateAll(Long devId, Integer furnaceNo, LocalDate someDate,String source) {
        if(!someDate.equals(LocalDate.now())) {
            generateShift(devId, furnaceNo, someDate,source);
        }
        TbCastingProductionReport.ReportTypeEnum reportTypeEnum =
            TbCastingProductionReport.ReportTypeEnum.DAILY;
        try {
            TbCastingProductionReport report = generateDaily(devId, furnaceNo, someDate,source);
            reportTypeEnum =
                TbCastingProductionReport.ReportTypeEnum.MONTHLY;
            generateMonth(devId, furnaceNo, someDate, report, reportTypeEnum,source);
            reportTypeEnum =
                TbCastingProductionReport.ReportTypeEnum.QUARTERLY;
            generateMonth(devId, furnaceNo, someDate, report, reportTypeEnum,source);
            reportTypeEnum =
                TbCastingProductionReport.ReportTypeEnum.YEARLY;
            generateMonth(devId, furnaceNo, someDate, report, reportTypeEnum,source);
            reportTypeEnum =
                TbCastingProductionReport.ReportTypeEnum.WEEKLY;
            generateMonth(devId, furnaceNo, someDate, report, reportTypeEnum,source);
        } catch (Throwable e) {
            log.info("生成报表失败{}--{}--{},失败原因{}", devId, furnaceNo, reportTypeEnum, e.getMessage());
        }
    }

    public void generateShift(Long deviceInternalId, Integer furnaceNo, LocalDate someDate,String source) {
        TbDeviceFurnace tbDeviceFurnace = tbDeviceFurnaceMapper.selectOneBy(deviceInternalId, furnaceNo);
        if (Objects.isNull(tbDeviceFurnace)) {
            return;
        }
        Integer reportType = 6;

        var shifts = tbCastingFurnaceOperatorShiftMapper.findShiftsByDate(deviceInternalId, furnaceNo, someDate);
        if (shifts.isEmpty()) {
            LocalDateTime[] cycleRange = castingProductionCycleService
                .getCycleRangeForDailyTask(deviceInternalId, furnaceNo, someDate);

            TbCastingFurnaceOperatorShift shift = new TbCastingFurnaceOperatorShift();
            shift.setDeviceInternalId(deviceInternalId);
            shift.setFurnaceNo(furnaceNo);
            shift.setShiftBeginAt(cycleRange[0]);
            shift.setShiftEndAt(cycleRange[1]);
            shifts.add(shift);
        }
        for (TbCastingFurnaceOperatorShift shift : shifts) {
            try {
                Long shiftId = shift.getId();
                TbCastingFurnaceChargeBatch chargeBatch = new TbCastingFurnaceChargeBatch();
                chargeBatch.setDeviceInternalId(deviceInternalId);
                chargeBatch.setFurnaceNo(furnaceNo);
                chargeBatch.setOperatorShiftId(shiftId);
                LocalDateTime cycleStartedAt = shift.getShiftBeginAt();
                LocalDateTime cycleEndedAt = shift.getShiftEndAt();
                BigDecimal fnPowerConsumption = BigDecimal.ZERO;
                BigDecimal fnPowerConsumptionSmelt = BigDecimal.ZERO;
                BigDecimal fnPowerConsumptionWarm = BigDecimal.ZERO;
                BigDecimal fnProduction = BigDecimal.ZERO;
                BigDecimal fnDuration = BigDecimal.ZERO;
                BigDecimal fnDurationSmelt = BigDecimal.ZERO;
                BigDecimal fnDurationWarm = BigDecimal.ZERO;
                int fnBatchCount = 0;
                Integer ladleBatchCountActual = 0;
                if (shiftId != null) {
                    List<TbCastingFurnaceChargeBatch> chargeBatches = tbCastingFurnaceChargeBatchMapper.selectList(Wrappers.lambdaQuery(chargeBatch));
                    fnBatchCount = chargeBatches.size();
                    ladleBatchCountActual = chargeBatches.stream().map(TbCastingFurnaceChargeBatch::getLadleBatchCountActual).reduce(0, Integer::sum);
                    List<TbFurnaceBatchAggregated> list = aggregatedBatchMapper.selectBatchListByShift(shiftId, deviceInternalId, furnaceNo);
                    fnPowerConsumption =
                        sumByAggregated(list, TbFurnaceBatchAggregated::getPowerConsumption);
                    fnPowerConsumptionSmelt =
                        sumByAggregated(list, TbFurnaceBatchAggregated::getSmeltPowerConsumption);
                    fnPowerConsumptionWarm =
                        sumByAggregated(list, TbFurnaceBatchAggregated::getHeatPreservationPowerConsumption);
                    fnProduction =
                        sumByCharge(chargeBatches, TbCastingFurnaceChargeBatch::getFnProduction);
                } else {
                    IotFurnaceCountMatlab entity = new IotFurnaceCountMatlab();
                    entity.setDeviceInternalId(deviceInternalId);
                    entity.setFurnaceNo(furnaceNo);

                    Wrapper<IotFurnaceCountMatlab> condition = Wrappers.lambdaQuery(entity)
                        .ge(IotFurnaceCountMatlab::getShutdownTime, ParamUtils.toEpochMilli(cycleStartedAt))
                        .lt(IotFurnaceCountMatlab::getShutdownTime, ParamUtils.toEpochMilli(cycleEndedAt))
                        .orderByAsc(IotFurnaceCountMatlab::getCreateTime);
                    List<IotFurnaceCountMatlab> list = iotFurnaceCountMatlabMapper.selectList(condition);
                    fnBatchCount = sumAnalogQuantityV2Utils.sumProductionCount(deviceInternalId, furnaceNo, someDate);
                    fnPowerConsumption =
                        sumByMatLab(list, IotFurnaceCountMatlab::getPowerConsumption);
                    fnPowerConsumptionSmelt =
                        sumByMatLab(list, IotFurnaceCountMatlab::getSmeltPowerConsumption);
                    fnPowerConsumptionWarm =
                        sumByMatLab(list, IotFurnaceCountMatlab::getHeatPreservationPowerConsumption);
                    fnDuration = sumByMatLabByLong(list,
                        IotFurnaceCountMatlab::getElapsedTime);
                    fnDurationSmelt =
                        sumByMatLabByLong(list, IotFurnaceCountMatlab::getSmeltTime);
                    fnDurationWarm =
                        sumByMatLabByLong(list, IotFurnaceCountMatlab::getHeatPreservationTime);
                }

                BigDecimal furnacePowerConsumption = BigDecimal.ZERO;
                Duration duration = Duration.between(
                    cycleStartedAt,
                    cycleEndedAt
                );
                if (duration.toDays() <= 2) {
                    //规避超过两天的炉次，比如忘了下班的情况
                    furnacePowerConsumption = sumAnalogQuantityV2Utils.getFurnacePowerConsumption(cycleStartedAt, cycleEndedAt, deviceInternalId, furnaceNo);
                } else {
                    cycleEndedAt = cycleStartedAt.plusMinutes(1);
                }

                TbCastingProductionReport report = new TbCastingProductionReport();
                report.setId(snowflakeIdGenerator.nextId());
                report.setDeviceInternalId(deviceInternalId);
                report.setFurnaceNo(furnaceNo);
                report.setReportType(reportType);
                report.setReportAt(TbCastingProductionReport.ReportTypeEnum.DAILY.getCalc().apply(someDate));
                report.setCycleStartedAt(cycleStartedAt);
                report.setCycleEndedAt(shift.getShiftEndAt());
                report.setOperatorShiftId(shiftId);

                TbCastingProductionReport.ReportData reportData = new TbCastingProductionReport.ReportData();
                reportData.setFnBatchCount(fnBatchCount);
                reportData.setLadleBatchCount(ladleBatchCountActual);
                reportData.setFnProduction(fnProduction);
                reportData.setFurnacePowerConsumption(furnacePowerConsumption);
                reportData.setFnPowerConsumption(fnPowerConsumption);
                reportData.setFnPowerConsumptionSmelt(fnPowerConsumptionSmelt);
                reportData.setFnPowerConsumptionWarm(fnPowerConsumptionWarm);
                reportData.setFnDuration(fnDuration);
                reportData.setFnDurationSmelt(fnDurationSmelt);
                reportData.setFnDurationWarm(fnDurationWarm);

                /*查询周期内的所有熔炼过程的仪器数据*/
                TbCastingProductionJournal.InstrumentTypeEnum instrumentTypeEnum = TbCastingProductionJournal.InstrumentTypeEnum.of(1);
                TbCastingProductionJournal.JournalBizTypeEnum journalBizTypeEnum = TbCastingProductionJournal.JournalBizTypeEnum.of(60);
                //碳硅分析仪-炉前
                reportData.setCsiAnalyzerRecordCount(
                    castingProductionJournalMapper.countByDateTime(deviceInternalId, furnaceNo,
                        instrumentTypeEnum,
                        null,
                        journalBizTypeEnum,
                        cycleStartedAt, cycleEndedAt)
                );
                reportData.setCsiAnalyzerRecordIdList(
                    SerializationUtils.toStr(
                        this.getIdListByDateTime(deviceInternalId, furnaceNo,
                            instrumentTypeEnum,
                            null,
                            journalBizTypeEnum,
                            cycleStartedAt, cycleEndedAt))
                );
                //炉前测温枪-炉前
                instrumentTypeEnum = TbCastingProductionJournal.InstrumentTypeEnum.of(2);
                journalBizTypeEnum = TbCastingProductionJournal.JournalBizTypeEnum.of(40);
                reportData.setTappingTempGunRecordCount(
                    castingProductionJournalMapper.countByDateTime(deviceInternalId, furnaceNo,
                        instrumentTypeEnum,
                        null,
                        journalBizTypeEnum,
                        cycleStartedAt, cycleEndedAt));
                reportData.setTappingTempGunRecordIdList(
                    SerializationUtils.toStr(
                        this.getIdListByDateTime(deviceInternalId, furnaceNo,
                            instrumentTypeEnum,
                            null,
                            journalBizTypeEnum,
                            cycleStartedAt, cycleEndedAt))
                );
                //加料吊钩秤-炉前
                instrumentTypeEnum = TbCastingProductionJournal.InstrumentTypeEnum.of(6);
