@RequiredArgsConstructor
@Slf4j
@Component
public class FurnaceServiceByShiftService {
    private final TbCastingFurnaceOperatorShiftMapper tbCastingFurnaceOperatorShiftMapper;
    private final TbCastingFurnaceChargeBatchMapper tbCastingFurnaceChargeBatchMapper;
    private final TbFurnaceBatchAggregatedMapper aggregatedBatchMapper;
    private final SumAnalogQuantityV2Utils sumAnalogQuantityV2Utils;
    private final CastingProductionCycleService castingProductionCycleService;

    private final CastingFurnaceAgeService furnaceAgeService;
    @Resource(name = "redisTemplate1")
    private RedisTemplate redisTemplate;//1号库

    public CountFurnaceDataByShift getProductFurnaceList(TbDeviceFurnace tbDeviceFurnace, LocalDate time) {
        Long deviceInternalId = tbDeviceFurnace.getDeviceInternalId();
        Integer furnaceNo = tbDeviceFurnace.getFnNo();

        CountFurnaceDataByShift data = new CountFurnaceDataByShift();
        Integer enableCharge = tbDeviceFurnace.getEnableCharge();
        var lastShift = tbCastingFurnaceOperatorShiftMapper.findLastShiftByDate(deviceInternalId, furnaceNo, time);

        //查今天最新的班次
        if (enableCharge == 1&&Objects.nonNull(lastShift)) {
            //查询最新班次加料炉次信息
            Long shiftId = lastShift.getId();
            data.setProductionOutput(tbCastingFurnaceChargeBatchMapper.sumProductionByShift(shiftId,deviceInternalId,furnaceNo));
            data.setProductionBatchCount(tbCastingFurnaceChargeBatchMapper.countByShift(shiftId,deviceInternalId,furnaceNo));
            data.setPowerConsumption(aggregatedBatchMapper.selectPowerConsumptionByShift(shiftId,deviceInternalId,furnaceNo));
            data.setCycleStartedAt(lastShift.getShiftBeginAt());
            data.setCycleEndedAt(lastShift.getShiftEndAt());
        } else {
            LocalDateTime[] cycleRange = castingProductionCycleService.getCycleRangeForAny(tbDeviceFurnace.getDeviceInternalId(), tbDeviceFurnace.getFnNo(), time);
            LocalDateTime cycleStartedAt = cycleRange[0];
            LocalDateTime cycleEndedAt = cycleRange[1];
            data.setProductionBatchCount(
                sumAnalogQuantityV2Utils.sumProductionCount(deviceInternalId, furnaceNo, time)
            );
            BigDecimal totalPowerConsumption = sumAnalogQuantityV2Utils.sumPowerConsumptionByFurnaceBatch(deviceInternalId, furnaceNo, time);
            data.setPowerConsumption(
                totalPowerConsumption
            );
            data.setCycleStartedAt(cycleStartedAt);
            data.setCycleEndedAt(cycleEndedAt);

            furnaceAgeService.obtainFurnaceAge(tbDeviceFurnace)
                .ifPresent(data::setFurnaceNumber);
        }
        //没有班次用周期
        return data;
    }
}

