    @ApiModelProperty("保温耗时(小时)")
    private BigDecimal preserveDuration;

    @ApiModelProperty("保温电费(元) = 保温基本电费 + 保温分时电费")
    private BigDecimal preserveCost;

    @ApiModelProperty("保温基本电费(元)")
    private BigDecimal preserveBasicCost;

    @ApiModelProperty("保温分时电费(元)")
    private BigDecimal preserveTimeSlotCost;

    /**
     * 累加电费明细(用于聚合)
     */
    public void add(ElectricityCostDetailVO other) {
        if (other == null) {
            return;
        }

        // 总计字段
        this.totalConsumption = addSafe(this.totalConsumption, other.totalConsumption);
        this.totalDuration = addSafe(this.totalDuration, other.totalDuration);

        // 熔炼阶段
        this.smeltConsumption = addSafe(this.smeltConsumption, other.smeltConsumption);
        this.smeltDuration = addSafe(this.smeltDuration, other.smeltDuration);
        this.smeltCost = addSafe(this.smeltCost, other.smeltCost);
        this.smeltBasicCost = addSafe(this.smeltBasicCost, other.smeltBasicCost);
        this.smeltTimeSlotCost = addSafe(this.smeltTimeSlotCost, other.smeltTimeSlotCost);

        // 保温阶段
        this.preserveConsumption = addSafe(this.preserveConsumption, other.preserveConsumption);
        this.preserveDuration = addSafe(this.preserveDuration, other.preserveDuration);
        this.preserveCost = addSafe(this.preserveCost, other.preserveCost);
        this.preserveBasicCost = addSafe(this.preserveBasicCost, other.preserveBasicCost);
        this.preserveTimeSlotCost = addSafe(this.preserveTimeSlotCost, other.preserveTimeSlotCost);
    }

    private BigDecimal addSafe(BigDecimal a, BigDecimal b) {
        BigDecimal val1 = a != null ? a : BigDecimal.ZERO;
        BigDecimal val2 = b != null ? b : BigDecimal.ZERO;
        return val1.add(val2);
    }
}

