        costDetail.setElectricity(aggregate.getTotalElectricity());
        costDetail.setElectricityCost(aggregate.getTotalElectricityCost());
        costDetail.setTotalCost(
            aggregate.getTotalMaterialCost().add(aggregate.getTotalElectricityCost())
        );

        // 产量
        costDetail.setProductionWeight(aggregate.getTotalProductionWeight());

        // 吨产指标（调用Entity的getter方法，实时计算）
        costDetail.setPerTonMaterialCost(aggregate.getPerTonMaterialCost());
        costDetail.setPerTonSmeltConsumption(aggregate.getPerTonSmeltConsumption());
        costDetail.setPerTonPreserveConsumption(aggregate.getPerTonPreserveConsumption());
        costDetail.setPerTonTotalElectricityCost(aggregate.getPerTonTotalElectricityCost());
        costDetail.setPerTonSmeltCost(aggregate.getPerTonSmeltCost());
        costDetail.setPerTonPreserveCost(aggregate.getPerTonPreserveCost());
        costDetail.setPerTonTotalCost(aggregate.getPerTonTotalCost());

        // 转换 BO 到 VO
        if (aggregate.getMaterialDetails() != null) {
            List<MaterialCostDetailVO> materials = CostBoConverter.toMaterialCostDetailVOList(
                aggregate.getMaterialDetails());
