    /**
     * 聚合物料明细: 按materialId分组聚合
     * <p>将多个班次的物料明细按物料ID分组,合并相同物料的重量和成本</p>
     */
    private List<MaterialCostDetailVO> aggregateMaterialDetails(List<TbFurnaceBatchCostShiftAggregate> shiftCosts) {
        // 收集所有物料明细并转换为 VO
        List<MaterialCostDetailVO> allMaterials = shiftCosts.stream()
            .map(TbFurnaceBatchCostShiftAggregate::getMaterialDetails)
            .filter(Objects::nonNull)
            .flatMap(boList -> {
                try {
                    List<MaterialCostDetailVO> materials = CostBoConverter.toMaterialCostDetailVOList(boList);
                    return materials != null ? materials.stream() : Stream.empty();
                } catch (Exception e) {
                    log.warn("转换物料明细BO失败", e);
                    return Stream.empty();
                }
            })
            .collect(Collectors.toList());

        if (allMaterials.isEmpty()) {
            return new ArrayList<>();
        }

        // 按materialId分组聚合
        Map<Long, MaterialCostDetailVO> materialMap = new HashMap<>();
        for (MaterialCostDetailVO material : allMaterials) {
            Long materialId = material.getMaterialId();
            if (materialId == null) {
                continue;
            }

            MaterialCostDetailVO existing = materialMap.get(materialId);
            if (existing == null) {
                // 第一次遇到该物料,创建新记录(包含batches明细)
                MaterialCostDetailVO aggregated = new MaterialCostDetailVO();
                aggregated.setMaterialId(material.getMaterialId());
                aggregated.setMaterialName(material.getMaterialName());
                aggregated.setTotalWeight(material.getTotalWeight() != null ? material.getTotalWeight() : BigDecimal.ZERO);
                aggregated.setTotalCost(material.getTotalCost() != null ? material.getTotalCost() : BigDecimal.ZERO);
                // 保留批次明细，如果有的话
                aggregated.setBatches(material.getBatches() != null ? new ArrayList<>(material.getBatches()) : new ArrayList<>());
                materialMap.put(materialId, aggregated);
            } else {
                // 累加重量和成本
                BigDecimal weight = material.getTotalWeight() != null ? material.getTotalWeight() : BigDecimal.ZERO;
                BigDecimal cost = material.getTotalCost() != null ? material.getTotalCost() : BigDecimal.ZERO;
                existing.setTotalWeight(existing.getTotalWeight().add(weight));
                existing.setTotalCost(existing.getTotalCost().add(cost));
                // 合并批次明细
                if (material.getBatches() != null && !material.getBatches().isEmpty()) {
                    if (existing.getBatches() == null) {
                        existing.setBatches(new ArrayList<>());
                    }
                    existing.getBatches().addAll(material.getBatches());
                }
            }
        }

        // 对每个物料的批次明细进行合并（按batchNo聚合）
        for (MaterialCostDetailVO material : materialMap.values()) {
            if (material.getBatches() != null && !material.getBatches().isEmpty()) {
                List<BatchCostDetailVO> mergedBatches = mergeBatchesByBatchNo(material.getBatches());
                material.setBatches(mergedBatches);
            }
        }

        // 按物料ID排序返回
        return materialMap.values().stream()
            .sorted(Comparator.comparing(MaterialCostDetailVO::getMaterialId))
            .collect(Collectors.toList());
    }

    /**
     * 聚合电费明细: 累加所有熔炼和保温数据
     */
    private ElectricityCostDetailVO aggregateElectricityDetails(List<TbFurnaceBatchCostShiftAggregate> shiftCosts) {
        ElectricityCostDetailVO aggregated = new ElectricityCostDetailVO();
        aggregated.setSmeltConsumption(BigDecimal.ZERO);
        aggregated.setSmeltCost(BigDecimal.ZERO);
        aggregated.setPreserveConsumption(BigDecimal.ZERO);
        aggregated.setPreserveCost(BigDecimal.ZERO);

        for (TbFurnaceBatchCostShiftAggregate shiftCost : shiftCosts) {
            if (shiftCost.getElectricityDetail() == null) {
                continue;
            }

            try {
                ElectricityCostDetailVO detail = CostBoConverter.toElectricityCostDetailVO(
                    shiftCost.getElectricityDetail());
                if (detail != null) {
                    aggregated.add(detail); // 使用ElectricityCostDetailVO自带的add方法
                }
            } catch (Exception e) {
                log.warn("转换电费明细BO失败", e);
            }
        }

        return aggregated;
    }

    /**
     * 构建炉次breakdown列表
     * <p>查询该班次+炉体下的所有加料炉次,并为每个炉次构建成本breakdown</p>
     */
    private List<CostBreakdownItem<FurnaceBatchDimensionInfo>> buildFurnaceBatchBreakdown(
        TbFurnaceBatchCostShiftAggregate furnaceAggregate, Integer furnaceNo) {

        Long shiftId = furnaceAggregate.getShiftId();

        // 查询该班次+炉体的所有加料炉次
        // 注意: 需要deviceInternalId,从班次信息获取
        TbCastingFurnaceOperatorShift shift = shiftMapper.selectById(shiftId);
        if (shift == null) {
            log.warn("班次不存在: shiftId={}", shiftId);
            return new ArrayList<>();
        }

        // 使用 TbFurnaceBatchCostDetail 查询该班次聚合下的所有炉次成本明细
        Long shiftAggregateId = furnaceAggregate.getId();
        List<TbFurnaceBatchCostDetail> costDetails = costDetailMapper.findByShiftAggregateId(shiftAggregateId);

        if (costDetails == null || costDetails.isEmpty()) {
            log.debug("该班次聚合无炉次成本明细数据: shiftAggregateId={}", shiftAggregateId);
            return new ArrayList<>();
        }

        // 构建炉次breakdown列表
        return costDetails.stream()
            .map(detail -> buildFurnaceBatchBreakdownItem(detail, furnaceAggregate))
            .collect(Collectors.toList());
    }

    /**
     * 为单个加料炉次构建breakdown项
     */
    private CostBreakdownItem<FurnaceBatchDimensionInfo> buildFurnaceBatchBreakdownItem(
        TbFurnaceBatchCostDetail costDetail,
        TbFurnaceBatchCostShiftAggregate furnaceAggregate) {

        CostBreakdownItem<FurnaceBatchDimensionInfo> item = new CostBreakdownItem<>();
        item.setDimensionType("furnace_batch");
        item.setDimensionId("batch_" + costDetail.getId());
        item.setDimensionLabel(String.format("第%d炉", costDetail.getBatchNo() != null ? costDetail.getBatchNo() : 0));

        // 维度信息
        FurnaceBatchDimensionInfo dimensionInfo = new FurnaceBatchDimensionInfo();
        dimensionInfo.setBatchNo(String.valueOf(costDetail.getBatchNo()));
        dimensionInfo.setStartTime(costDetail.getBatchStartedAt());
        dimensionInfo.setEndTime(costDetail.getBatchEndedAt());

        // 炉次状态: 如果有结束时间则为已完成,否则为进行中
        if (costDetail.getBatchEndedAt() != null) {
            dimensionInfo.setStatus(2); // 已完成
            dimensionInfo.setStatusLabel("已完成");
        } else {
            dimensionInfo.setStatus(1); // 进行中
            dimensionInfo.setStatusLabel("进行中");
        }

