        QueryFurnaceReportVo vo = new QueryFurnaceReportVo();
        vo.setBatchId(batchId);
        vo.setBatchNo(batchNo);
        vo.setBatchStartedAt(LocalDateTime.parse(startAt));
        vo.setBatchEndedAt(LocalDateTime.parse(startAt).plusMinutes(30));
        vo.setFnDuration(new BigDecimal("30"));
        vo.setFnPowerConsumption(new BigDecimal("12.50"));
        vo.setLadleBatchCount(3);
        vo.setLadleBatchCountActual(2);
        return vo;
    }

    private static QueryFurnaceReportVo detailedReportItem(String batchId, Integer batchNo, String startAt) {
        QueryFurnaceReportVo vo = reportItem(batchId, batchNo, startAt);
        vo.setFurnaceChargePreTappingSummary(Collections.singletonList(nameValue("废钢", "11.50")));
