        vo.setTappingWeightList(Collections.singletonList(weightRecord("2026-02-28T10:25:00", "11.50")));
        return vo;
    }

    private static NameDecimalValueBo nameValue(String name, String actual) {
        NameDecimalValueBo value = new NameDecimalValueBo();
        value.setName(name);
        value.setActual(new BigDecimal(actual));
        value.setUnit("kg");
        return value;
    }

    private static TbCastingProductionBatch.WeightRecord weightRecord(String addedAt, String actual) {
