    private void appendChargeAbnormalities(List<BatchAbnormality> abnormalities,
                                           String stageName,
                                           List<NameDecimalValueBo> details) {
        if (details == null || details.isEmpty()) {
            return;
        }

        List<String> nonPositiveItems = new ArrayList<>();
        List<String> targetMismatchItems = new ArrayList<>();
        for (NameDecimalValueBo item : details) {
            if (item == null) {
                continue;
            }
            if (item.getActual() != null && item.getActual().compareTo(BigDecimal.ZERO) <= 0) {
                nonPositiveItems.add(item.getName() + "=" + toPlainString(item.getActual()));
            }
            if (isOutsideTarget(item.getActual(), item.getTargetLowerLimit(), item.getTargetUpperLimit())) {
                targetMismatchItems.add(buildTargetRangeMessage(item.getName(), item.getActual(),
                    item.getTargetLowerLimit(), item.getTargetUpperLimit()));
            } else if (item.getTargetValue() != null && item.getActual() != null
                && item.getActual().compareTo(item.getTargetValue()) != 0) {
                targetMismatchItems.add(item.getName() + " 实际=" + toPlainString(item.getActual())
                    + "，目标=" + toPlainString(item.getTargetValue()));
            }
        }
        if (!nonPositiveItems.isEmpty()) {
            abnormalities.add(new BatchAbnormality(
                "charge_abnormal",
                stageName + "存在异常加料值",
                limitJoined(nonPositiveItems)
            ));
        }
        if (!targetMismatchItems.isEmpty()) {
            abnormalities.add(new BatchAbnormality(
                "target_mismatch",
                stageName + "目标值不匹配",
                limitJoined(targetMismatchItems)
            ));
        }
    }

