    private String limitJoined(List<String> items) {
        if (items == null || items.isEmpty()) {
            return "";
        }
        List<String> limited = items.size() > 3 ? items.subList(0, 3) : items;
        String suffix = items.size() > 3 ? " 等" + items.size() + "项" : "";
        return String.join("；", limited) + suffix;
    }

    private String buildBatchSummaryText(QueryFurnaceReportVo record,
                                         ObjectNode metrics,
                                         List<BatchAbnormality> abnormalities) {
        List<String> parts = new ArrayList<>();
        parts.add("第" + defaultInt(record.getBatchNo()) + "炉");
        if (record.getBatchStartedAt() != null) {
            parts.add("开始时间" + formatDateTime(record.getBatchStartedAt()));
        }
        if (record.getBatchEndedAt() != null) {
            parts.add("结束时间" + formatDateTime(record.getBatchEndedAt()));
        }
        if (record.getFnDuration() != null) {
            parts.add("耗时" + toPlainString(record.getFnDuration()) + "分钟");
        }
        if (record.getFnPowerConsumption() != null) {
            parts.add("耗电" + toPlainString(record.getFnPowerConsumption()));
        }
        if (record.getLadleBatchCount() != null || record.getLadleBatchCountActual() != null) {
            parts.add("目标包次/实际包次=" + defaultInt(record.getLadleBatchCount())
                + "/" + defaultInt(record.getLadleBatchCountActual()));
        }
        if (metrics.hasNonNull("latestTappingTemperature")) {
            parts.add("最新出炉温度=" + metrics.path("latestTappingTemperature").asText());
        }
        if (metrics.hasNonNull("latestTappingWeight")) {
            parts.add("最新出炉重量=" + metrics.path("latestTappingWeight").asText());
        }
        if (abnormalities.isEmpty()) {
            parts.add("未识别到明显异常");
        } else {
            parts.add("识别到异常: " + abnormalities.stream()
                .map(item -> item.title)
                .distinct()
                .limit(3)
                .reduce((left, right) -> left + "；" + right)
                .orElse(""));
        }
        return String.join("，", parts);
    }

