package com.allthinkstars.framework.iot.ai.tools.report;

import com.allthinkstars.framework.iot.erp.datasource.entities.TbProdPlan;
import com.allthinkstars.framework.iot.erp.datasource.mappers.TbProdPlanFurnaceMapper;
import com.allthinkstars.framework.iot.erp.datasource.mappers.TbProdPlanMapper;
import com.allthinkstars.framework.iot.erp.service.CastingFurnaceProductionPlanService;
import com.allthinkstars.framework.iot.erp.vo.plan.CastingPlanBatchDetailVo;
import com.allthinkstars.framework.iot.erp.vo.plan.CastingPlanLadleDetailVo;
import com.allthinkstars.framework.iot.nextg.entity.TbCastingFurnaceOperatorShift;
import com.allthinkstars.framework.iot.nextg.entity.TbDeviceFurnace;
import com.allthinkstars.framework.iot.nextg.entity.TbFurnaceBatchAggregated;
import com.allthinkstars.framework.iot.nextg.mapper.TbCastingFurnaceOperatorShiftMapper;
import com.allthinkstars.framework.iot.nextg.repo.TbFurnaceBatchAggregatedRepo;
import com.baomidou.mybatisplus.core.toolkit.CollectionUtils;
