import com.ruoyi.common.exception.ServiceException;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.Collections;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Optional;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
public class AiFurnaceBatchOverviewReportService {

    private static final DateTimeFormatter TIME_RANGE_FORMATTER = DateTimeFormatter.ofPattern("HH:mm");
    private static final BigDecimal ONE_THOUSAND = BigDecimal.valueOf(1000L);

    private final TbFurnaceBatchAggregatedRepo aggregatedRepo;
    private final TbCastingFurnaceOperatorShiftMapper shiftMapper;
    private final CastingFurnaceProductionPlanService planService;
    private final TbProdPlanMapper prodPlanMapper;
    private final TbProdPlanFurnaceMapper prodPlanFurnaceMapper;

    public AiFurnaceBatchOverviewReport buildReport(
        TbDeviceFurnace targetFurnace,
        LocalDate targetDate,
        Long shiftId,
        Long tenantId
    ) {
        List<TbFurnaceBatchAggregated> aggregatedBatches = queryAggregatedBatches(targetFurnace, targetDate, shiftId);
        TbCastingFurnaceOperatorShift shift = shiftId == null ? null : resolveShift(shiftId, targetFurnace);

        Map<Long, BigDecimal> planTappingWeightByBatchId = resolvePlanTappingWeightMap(aggregatedBatches);

        AiFurnaceBatchOverviewReport report = new AiFurnaceBatchOverviewReport();
        report.setSummary(buildSummary(aggregatedBatches, targetFurnace, targetDate, shift, tenantId));
        report.setBatches(buildBatchRows(aggregatedBatches, planTappingWeightByBatchId));
        return report;
    }

    private List<TbFurnaceBatchAggregated> queryAggregatedBatches(
        TbDeviceFurnace targetFurnace,
        LocalDate targetDate,
        Long shiftId
    ) {
        if (shiftId != null) {
            resolveShift(shiftId, targetFurnace);
            return aggregatedRepo.selectBatchListByShift(
                shiftId,
                targetFurnace.getDeviceInternalId(),
                targetFurnace.getFnNo()
            );
        }
        return aggregatedRepo.selectBatchListByBatchDate(
            targetDate,
            targetFurnace.getDeviceInternalId(),
            targetFurnace.getFnNo()
        );
    }

    private TbCastingFurnaceOperatorShift resolveShift(Long shiftId, TbDeviceFurnace targetFurnace) {
        TbCastingFurnaceOperatorShift shift = shiftMapper.selectById(shiftId);
        if (shift == null) {
            throw new ServiceException("班次不存在: shiftId=" + shiftId);
        }
        if (!Objects.equals(shift.getDeviceInternalId(), targetFurnace.getDeviceInternalId())
            || !Objects.equals(shift.getFurnaceNo(), targetFurnace.getFnNo())) {
            throw new ServiceException("班次与目标炉体不匹配: shiftId=" + shiftId);
        }
        return shift;
    }

    private AiFurnaceBatchOverviewSummary buildSummary(
        List<TbFurnaceBatchAggregated> aggregatedBatches,
        TbDeviceFurnace targetFurnace,
        LocalDate targetDate,
        TbCastingFurnaceOperatorShift shift,
        Long tenantId
    ) {
        AiFurnaceBatchOverviewSummary summary = new AiFurnaceBatchOverviewSummary();
        BigDecimal totalPowerConsumption = sumBatches(aggregatedBatches, TbFurnaceBatchAggregated::getPowerConsumption);
        BigDecimal totalProductionWeight = sumBatches(aggregatedBatches, TbFurnaceBatchAggregated::getTappingWeight);
        BigDecimal totalChargeWeight = sumBatches(aggregatedBatches, TbFurnaceBatchAggregated::getFnChargeWeight);

        summary.setPlannedBatchCount(countPlannedBatches(targetFurnace, targetDate, shift, tenantId));
        summary.setBatchCount(aggregatedBatches.size());
        summary.setCompletedBatchCount((int) aggregatedBatches.stream()
            .filter(Objects::nonNull)
            .filter(batch -> batch.getBatchEndedAt() != null)
            .count());
        summary.setTotalPowerConsumption(totalPowerConsumption);
        summary.setTotalProductionWeight(totalProductionWeight);
        summary.setTotalChargeWeight(totalChargeWeight);
        BigDecimal avgTonPower = calculateTonPowerConsumption(totalPowerConsumption, totalProductionWeight);
        summary.setAvgTonPowerConsumption(avgTonPower);

        Map<String, Integer> abnormalSignals = new LinkedHashMap<>();
        abnormalSignals.put("highPowerConsume", countHighPowerConsume(aggregatedBatches, avgTonPower));
        summary.setTopAbnormalSignals(abnormalSignals);
        return summary;
    }

    private Integer countPlannedBatches(
        TbDeviceFurnace targetFurnace,
        LocalDate targetDate,
        TbCastingFurnaceOperatorShift shift,
        Long tenantId
    ) {
        List<Long> planIds;
        if (shift != null && CollectionUtils.isNotEmpty(shift.getPlanIds())) {
            planIds = prodPlanMapper.selectList(Wrappers.lambdaQuery(TbProdPlan.class)
                    .in(TbProdPlan::getId, shift.getPlanIds())
                    .eq(TbProdPlan::getDeviceInternalId, targetFurnace.getDeviceInternalId())
                    .eq(TbProdPlan::getFurnaceNo, targetFurnace.getFnNo())
                    .eq(tenantId != null, TbProdPlan::getTenantId, tenantId))
                .stream()
                .map(TbProdPlan::getId)
                .collect(Collectors.toList());
        } else {
            planIds = prodPlanMapper.selectList(Wrappers.lambdaQuery(TbProdPlan.class)
                    .eq(TbProdPlan::getPlanDate, targetDate)
                    .eq(TbProdPlan::getDeviceInternalId, targetFurnace.getDeviceInternalId())
                    .eq(TbProdPlan::getFurnaceNo, targetFurnace.getFnNo())
                    .eq(tenantId != null, TbProdPlan::getTenantId, tenantId))
                .stream()
                .map(TbProdPlan::getId)
                .collect(Collectors.toList());
        }

        if (CollectionUtils.isEmpty(planIds)) {
            return 0;
        }
        Long count = prodPlanFurnaceMapper.selectCount(
            Wrappers.lambdaQuery(com.allthinkstars.framework.iot.erp.datasource.entities.TbProdPlanFurnace.class)
                .in(com.allthinkstars.framework.iot.erp.datasource.entities.TbProdPlanFurnace::getPlanId, planIds)
        );
        return count == null ? 0 : count.intValue();
    }

    private Map<Long, BigDecimal> resolvePlanTappingWeightMap(List<TbFurnaceBatchAggregated> aggregatedBatches) {
        if (CollectionUtils.isEmpty(aggregatedBatches)) {
            return Collections.emptyMap();
        }
        Map<Long, BigDecimal> planTappingWeightMap = new LinkedHashMap<>();
        List<Long> planBatchIds = aggregatedBatches.stream()
            .map(TbFurnaceBatchAggregated::getPlanBatchId)
            .filter(Objects::nonNull)
            .distinct()
            .collect(Collectors.toList());
        for (Long planBatchId : planBatchIds) {
            BigDecimal planTappingWeight = planService.getPlanBatchDetailByPlanBatchId(planBatchId)
                .map(this::sumPlanTappingWeight)
                .orElse(BigDecimal.ZERO);
            planTappingWeightMap.put(planBatchId, planTappingWeight);
        }
        return planTappingWeightMap;
    }

    private BigDecimal sumPlanTappingWeight(CastingPlanBatchDetailVo detailVo) {
        if (detailVo == null || detailVo.getLadlePlanDetails() == null) {
            return BigDecimal.ZERO;
        }
        return detailVo.getLadlePlanDetails().stream()
            .filter(Objects::nonNull)
            .map(CastingPlanLadleDetailVo::getPlanTappingWeight)
            .filter(Objects::nonNull)
            .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    private List<AiFurnaceBatchOverviewBatch> buildBatchRows(
        List<TbFurnaceBatchAggregated> aggregatedBatches,
        Map<Long, BigDecimal> planTappingWeightByBatchId
    ) {
        if (CollectionUtils.isEmpty(aggregatedBatches)) {
            return Collections.emptyList();
        }
        List<AiFurnaceBatchOverviewBatch> rows = new ArrayList<>(aggregatedBatches.size());
        for (TbFurnaceBatchAggregated aggregatedBatch : aggregatedBatches) {
            AiFurnaceBatchOverviewBatch row = new AiFurnaceBatchOverviewBatch();
            row.setFactoryBatchCode(resolveFactoryBatchCode(aggregatedBatch));
            row.setAggregatedBatchId(aggregatedBatch.getId());
            row.setBatchNo(aggregatedBatch.getBatchNo());
            row.setBatchStartEnd(formatBatchStartEnd(aggregatedBatch.getBatchStartedAt(), aggregatedBatch.getBatchEndedAt()));
            row.setTotalChargeWeight(defaultZero(aggregatedBatch.getFnChargeWeight()));
            row.setTappingWeight(defaultZero(aggregatedBatch.getTappingWeight()));
            row.setPlanTappingWeight(defaultZero(planTappingWeightByBatchId.get(aggregatedBatch.getPlanBatchId())));
            row.setPowerConsumption(defaultZero(aggregatedBatch.getPowerConsumption()));
            rows.add(row);
        }
        return rows;
    }

    private int countHighPowerConsume(List<TbFurnaceBatchAggregated> aggregatedBatches, BigDecimal avgTonPower) {
        if (CollectionUtils.isEmpty(aggregatedBatches) || avgTonPower == null || avgTonPower.compareTo(BigDecimal.ZERO) <= 0) {
            return 0;
        }
        BigDecimal threshold = avgTonPower.multiply(new BigDecimal("1.2"));
        int count = 0;
        for (TbFurnaceBatchAggregated batch : aggregatedBatches) {
            BigDecimal tonPower = calculateTonPowerConsumption(
                defaultZero(batch.getPowerConsumption()),
                defaultZero(batch.getTappingWeight())
            );
            if (tonPower.compareTo(threshold) > 0) {
                count++;
            }
        }
        return count;
    }

    private BigDecimal calculateTonPowerConsumption(BigDecimal powerConsumption, BigDecimal tappingWeight) {
        if (powerConsumption == null || tappingWeight == null || tappingWeight.compareTo(BigDecimal.ZERO) <= 0) {
            return BigDecimal.ZERO;
        }
        return powerConsumption.multiply(ONE_THOUSAND)
            .divide(tappingWeight, 1, RoundingMode.HALF_UP);
    }

    private BigDecimal sumBatches(
        List<TbFurnaceBatchAggregated> aggregatedBatches,
        java.util.function.Function<TbFurnaceBatchAggregated, BigDecimal> extractor
    ) {
        if (CollectionUtils.isEmpty(aggregatedBatches)) {
            return BigDecimal.ZERO;
        }
        return aggregatedBatches.stream()
            .filter(Objects::nonNull)
            .map(extractor)
            .filter(Objects::nonNull)
            .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    private String resolveFactoryBatchCode(TbFurnaceBatchAggregated aggregatedBatch) {
        String code = Optional.ofNullable(aggregatedBatch.getFactoryBatchCode()).map(String::trim).orElse("");
        if (!code.isEmpty()) {
            return code;
        }
        return aggregatedBatch.getBatchNo() == null ? "" : String.valueOf(aggregatedBatch.getBatchNo());
    }

    private String formatBatchStartEnd(LocalDateTime start, LocalDateTime end) {
        String startText = start == null ? "--" : TIME_RANGE_FORMATTER.format(start);
        String endText = end == null ? "--" : TIME_RANGE_FORMATTER.format(end);
        return startText + " - " + endText;
    }

    private BigDecimal defaultZero(BigDecimal value) {
        return value == null ? BigDecimal.ZERO : value;
    }
}

