@RunWith(MockitoJUnitRunner.class)
public class AiFurnaceBatchOverviewReportServiceTest {

    @Mock
    private TbFurnaceBatchAggregatedRepo aggregatedRepo;

    @Mock
    private TbCastingFurnaceOperatorShiftMapper shiftMapper;

    @Mock
    private CastingFurnaceProductionPlanService planService;

    @Mock
    private TbProdPlanMapper prodPlanMapper;

    @Mock
    private TbProdPlanFurnaceMapper prodPlanFurnaceMapper;

    private AiFurnaceBatchOverviewReportService service;

    @Before
    public void setUp() {
        service = new AiFurnaceBatchOverviewReportService(
            aggregatedRepo,
            shiftMapper,
            planService,
            prodPlanMapper,
            prodPlanFurnaceMapper
        );
    }

    @Test
    public void buildReport_shouldAssembleDateOverviewWithStableOrderingAndDefaults() {
        TbDeviceFurnace furnace = furnace(100L, 1);
        LocalDate targetDate = LocalDate.parse("2026-03-10");

        TbFurnaceBatchAggregated first = aggregatedBatch(101L, 1, "20260310-01",
            LocalDateTime.parse("2026-03-10T08:12:00"), LocalDateTime.parse("2026-03-10T09:26:00"),
            new BigDecimal("5100.0"), new BigDecimal("4820.0"), new BigDecimal("545.0"), 201L);
        TbFurnaceBatchAggregated second = aggregatedBatch(102L, 2, "20260310-02",
            LocalDateTime.parse("2026-03-10T10:00:00"), null,
            null, null, null, null);
        when(aggregatedRepo.selectBatchListByBatchDate(targetDate, 100L, 1))
            .thenReturn(Arrays.asList(first, second));

        TbProdPlan plan = new TbProdPlan();
        plan.setId(301L);
        when(prodPlanMapper.selectList(any())).thenReturn(Collections.singletonList(plan));
        when(prodPlanFurnaceMapper.selectCount(any())).thenReturn(2L);

        CastingPlanBatchDetailVo planDetail = new CastingPlanBatchDetailVo();
        CastingPlanLadleDetailVo ladleOne = new CastingPlanLadleDetailVo();
        ladleOne.setPlanTappingWeight(new BigDecimal("2400.0"));
        CastingPlanLadleDetailVo ladleTwo = new CastingPlanLadleDetailVo();
        ladleTwo.setPlanTappingWeight(new BigDecimal("2400.0"));
        planDetail.setLadlePlanDetails(Arrays.asList(ladleOne, ladleTwo));
        when(planService.getPlanBatchDetailByPlanBatchId(201L)).thenReturn(Optional.of(planDetail));

        AiFurnaceBatchOverviewReport report = service.buildReport(furnace, targetDate, null, 88L);

        Assert.assertNotNull(report);
        Assert.assertNotNull(report.getSummary());
        Assert.assertEquals(Integer.valueOf(2), report.getSummary().getPlannedBatchCount());
        Assert.assertEquals(Integer.valueOf(2), report.getSummary().getBatchCount());
        Assert.assertEquals(Integer.valueOf(1), report.getSummary().getCompletedBatchCount());
        Assert.assertEquals(new BigDecimal("545.0"), report.getSummary().getTotalPowerConsumption());
        Assert.assertEquals(new BigDecimal("4820.0"), report.getSummary().getTotalProductionWeight());
        Assert.assertEquals(new BigDecimal("5100.0"), report.getSummary().getTotalChargeWeight());
        Assert.assertEquals(new BigDecimal("113.1"), report.getSummary().getAvgTonPowerConsumption());
        Assert.assertEquals(Integer.valueOf(0), report.getSummary().getTopAbnormalSignals().get("highPowerConsume"));

        Assert.assertEquals(2, report.getBatches().size());
        Assert.assertEquals(Long.valueOf(101L), report.getBatches().get(0).getAggregatedBatchId());
        Assert.assertEquals("20260310-01", report.getBatches().get(0).getFactoryBatchCode());
        Assert.assertEquals("08:12 - 09:26", report.getBatches().get(0).getBatchStartEnd());
        Assert.assertEquals(new BigDecimal("4800.0"), report.getBatches().get(0).getPlanTappingWeight());
        Assert.assertEquals(Long.valueOf(102L), report.getBatches().get(1).getAggregatedBatchId());
        Assert.assertEquals("10:00 - --", report.getBatches().get(1).getBatchStartEnd());
        Assert.assertEquals(BigDecimal.ZERO, report.getBatches().get(1).getTotalChargeWeight());
        Assert.assertEquals(BigDecimal.ZERO, report.getBatches().get(1).getTappingWeight());
        Assert.assertEquals(BigDecimal.ZERO, report.getBatches().get(1).getPlanTappingWeight());
        Assert.assertEquals(BigDecimal.ZERO, report.getBatches().get(1).getPowerConsumption());

        verify(aggregatedRepo).selectBatchListByBatchDate(targetDate, 100L, 1);
        verify(aggregatedRepo, never()).selectBatchListByShift(any(), any(), any());
    }

    @Test
    public void buildReport_shouldUseShiftScopeAndCountHighPowerConsumeFromPlanIds() {
        TbDeviceFurnace furnace = furnace(100L, 1);
        TbCastingFurnaceOperatorShift shift = new TbCastingFurnaceOperatorShift();
        shift.setId(900L);
        shift.setDeviceInternalId(100L);
        shift.setFurnaceNo(1);
        shift.setPlans("[401,402]");
        when(shiftMapper.selectById(900L)).thenReturn(shift);

        TbFurnaceBatchAggregated low = aggregatedBatch(201L, 1, "B-01",
            LocalDateTime.parse("2026-03-10T08:00:00"), LocalDateTime.parse("2026-03-10T09:00:00"),
            new BigDecimal("5000.0"), new BigDecimal("5000.0"), new BigDecimal("500.0"), 501L);
        TbFurnaceBatchAggregated high = aggregatedBatch(202L, 2, "B-02",
            LocalDateTime.parse("2026-03-10T09:10:00"), LocalDateTime.parse("2026-03-10T10:10:00"),
            new BigDecimal("5000.0"), new BigDecimal("2500.0"), new BigDecimal("500.0"), 502L);
        when(aggregatedRepo.selectBatchListByShift(900L, 100L, 1)).thenReturn(Arrays.asList(low, high));

        TbProdPlan planOne = new TbProdPlan();
        planOne.setId(401L);
        TbProdPlan planTwo = new TbProdPlan();
        planTwo.setId(402L);
        when(prodPlanMapper.selectList(any())).thenReturn(Arrays.asList(planOne, planTwo));
        when(prodPlanFurnaceMapper.selectCount(any())).thenReturn(3L);
        when(planService.getPlanBatchDetailByPlanBatchId(eq(501L))).thenReturn(Optional.empty());
        when(planService.getPlanBatchDetailByPlanBatchId(eq(502L))).thenReturn(Optional.empty());

        AiFurnaceBatchOverviewReport report = service.buildReport(furnace, LocalDate.parse("2026-03-10"), 900L, 88L);

        Assert.assertEquals(Integer.valueOf(3), report.getSummary().getPlannedBatchCount());
        Assert.assertEquals(Integer.valueOf(2), report.getSummary().getBatchCount());
        Assert.assertEquals(Integer.valueOf(2), report.getSummary().getCompletedBatchCount());
        Assert.assertEquals(new BigDecimal("133.3"), report.getSummary().getAvgTonPowerConsumption());
        Assert.assertEquals(Integer.valueOf(1), report.getSummary().getTopAbnormalSignals().get("highPowerConsume"));
        verify(aggregatedRepo).selectBatchListByShift(900L, 100L, 1);
        verify(shiftMapper).selectById(900L);
        verify(prodPlanMapper).selectList(any());
        verify(prodPlanFurnaceMapper).selectCount(any());
    }

    @Test
    public void buildReport_shouldReturnZeroWeightedAverageWhenNoProduction() {
        TbDeviceFurnace furnace = furnace(100L, 1);
        LocalDate targetDate = LocalDate.parse("2026-03-10");

        TbFurnaceBatchAggregated batch = aggregatedBatch(301L, 1, "B-01",
            LocalDateTime.parse("2026-03-10T08:00:00"), null,
            new BigDecimal("5000.0"), BigDecimal.ZERO, new BigDecimal("500.0"), null);
        when(aggregatedRepo.selectBatchListByBatchDate(targetDate, 100L, 1))
            .thenReturn(Collections.singletonList(batch));
        when(prodPlanMapper.selectList(any())).thenReturn(Collections.emptyList());

        AiFurnaceBatchOverviewReport report = service.buildReport(furnace, targetDate, null, 88L);

        Assert.assertEquals(Integer.valueOf(0), report.getSummary().getPlannedBatchCount());
        Assert.assertEquals(BigDecimal.ZERO, report.getSummary().getAvgTonPowerConsumption());
        Assert.assertEquals(Integer.valueOf(0), report.getSummary().getTopAbnormalSignals().get("highPowerConsume"));
        Assert.assertEquals(BigDecimal.ZERO, report.getBatches().get(0).getPlanTappingWeight());
        verify(prodPlanFurnaceMapper, never()).selectCount(any());
    }

    private TbDeviceFurnace furnace(Long deviceInternalId, Integer furnaceNo) {
        TbDeviceFurnace furnace = new TbDeviceFurnace();
        furnace.setDeviceInternalId(deviceInternalId);
        furnace.setFnNo(furnaceNo);
        furnace.setFnCode(String.valueOf(furnaceNo));
        return furnace;
    }

    private TbFurnaceBatchAggregated aggregatedBatch(
        Long id,
        Integer batchNo,
        String factoryBatchCode,
        LocalDateTime batchStartedAt,
        LocalDateTime batchEndedAt,
        BigDecimal chargeWeight,
        BigDecimal tappingWeight,
        BigDecimal powerConsumption,
        Long planBatchId
    ) {
        TbFurnaceBatchAggregated batch = new TbFurnaceBatchAggregated();
        batch.setId(id);
        batch.setBatchNo(batchNo);
        batch.setFactoryBatchCode(factoryBatchCode);
        batch.setBatchStartedAt(batchStartedAt);
        batch.setBatchEndedAt(batchEndedAt);
        batch.setFnChargeWeight(chargeWeight);
        batch.setTappingWeight(tappingWeight);
        batch.setPowerConsumption(powerConsumption);
        batch.setPlanBatchId(planBatchId);
        return batch;
    }
}

