package com.allthinkstars.framework.iot.ai.tools;

import com.allthinkstars.framework.iot.ai.tools.support.AiRunContext;
import com.allthinkstars.framework.iot.ai.tools.support.annotation.AiToolDef;
import com.allthinkstars.framework.iot.ai.tools.support.annotation.AiToolParam;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ObjectNode;
import lombok.extern.slf4j.Slf4j;
import org.yaml.snakeyaml.Yaml;

import java.io.InputStream;
import java.lang.reflect.Method;
import java.lang.reflect.Parameter;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.Iterator;
import java.util.LinkedHashMap;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Set;

@Slf4j
public class ToolRegistry {

    private static final String DEFAULT_PROMPT_FILE = "config/ai/tool-prompts.yml";
    private static final String ENV_PROMPT_FILE = "AI_TOOL_PROMPTS_FILE";
    private static final String SYS_PROP_PROMPT_FILE = "ai.tool.prompts.file";

    private final Map<String, ToolMethod> methods = new LinkedHashMap<>();
    private final Map<String, ToolSpec> specs = new LinkedHashMap<>();
    private final Map<String, PromptOverride> promptOverrides;

    public ToolRegistry() {
        this.promptOverrides = loadPromptOverrides();
    }

    /**
     * 扫描并注册注解式工具方法。
     * 注册时会一次性构建：
     * - 可执行方法描述(ToolMethod)
     * - 对外暴露的工具元信息(ToolSpec)
     */
    public void registerAnnotatedBean(ObjectMapper objectMapper, Object toolBean) {
        if (toolBean == null || objectMapper == null) {
            return;
        }
        for (Method method : toolBean.getClass().getDeclaredMethods()) {
            AiToolDef toolDef = method.getAnnotation(AiToolDef.class);
            if (toolDef == null) {
                continue;
            }
            ToolMethod toolMethod = ToolMethod.of(objectMapper, toolBean, method, toolDef);
            String toolName = toolMethod.spec().getName();
            ToolSpec resolvedSpec = withPromptOverrides(toolMethod.spec().copy());
            // 同名后注册会覆盖前者，作为显式白名单更新机制。
            methods.put(toolName, toolMethod.withSpec(resolvedSpec));
            specs.put(toolName, resolvedSpec);
        }
    }

    /**
     * 工具统一调用入口，负责将异常归一为稳定错误码。
     */
    public ToolResult invoke(String toolName, JsonNode args, AiRunContext ctx) {
        ToolMethod method = methods.get(toolName);
        if (method == null) {
            return ToolResult.fail("tool_not_allowed", "工具不在白名单: " + toolName);
        }
        try {
            return method.invoke(args, ctx);
        } catch (IllegalArgumentException e) {
            String msg = e.getMessage() == null ? e.toString() : e.getMessage();
            if (msg.startsWith("缺少必填参数:")) {
                String missing = msg.substring("缺少必填参数:".length()).trim();
                return ToolResult.fail("tool_args_missing", msg, method.missingArgData(args, missing));
            }
            return ToolResult.fail("tool_args_invalid", msg, method.invalidArgData(args));
        } catch (Exception e) {
            String msg = e.getMessage() == null ? e.toString() : e.getMessage();
            return ToolResult.fail("tool_exec_error", msg, method.execErrorData(args, msg));
        }
    }

    /**
     * 返回可用于 tools/list 的工具定义快照。
     */
    public List<ToolSpec> listToolSpecs() {
        return new ArrayList<>(specs.values());
    }

    private ToolSpec withPromptOverrides(ToolSpec spec) {
        PromptOverride toolOverride = promptOverrides.get(spec.getName());
        if (toolOverride == null) {
            return spec;
        }
        if (toolOverride.description != null && !toolOverride.description.isBlank()) {
            spec.setDescription(toolOverride.description);
        }
        if (toolOverride.params != null && !toolOverride.params.isEmpty() && spec.getParameters() != null) {
            for (ToolParamSpec param : spec.getParameters()) {
                String desc = toolOverride.params.get(param.getName());
                if (desc != null && !desc.isBlank()) {
                    param.setDescription(desc);
                }
            }
        }
        if (toolOverride.result != null) {
            ToolResultSpec resultSpec = spec.getResult();
            if (resultSpec == null) {
                resultSpec = new ToolResultSpec();
                spec.setResult(resultSpec);
            }
            if (toolOverride.result.description != null && !toolOverride.result.description.isBlank()) {
                resultSpec.setDescription(toolOverride.result.description);
            }
            if (!toolOverride.result.fields.isEmpty()) {
                Map<String, String> fields = resultSpec.getFields();
                if (fields == null) {
                    fields = new LinkedHashMap<>();
                    resultSpec.setFields(fields);
                }
                fields.putAll(toolOverride.result.fields);
            }
        }
        return spec;
    }

    private Map<String, PromptOverride> loadPromptOverrides() {
        Path file = resolvePromptFile();
        if (!Files.exists(file)) {
            return Collections.emptyMap();
        }
        try (InputStream in = Files.newInputStream(file)) {
            Object root = new Yaml().load(in);
            if (!(root instanceof Map)) {
                return Collections.emptyMap();
            }
            Object overridesObj = ((Map<?, ?>) root).get("overrides");
            if (!(overridesObj instanceof Map)) {
                return Collections.emptyMap();
            }
            Map<String, PromptOverride> out = new LinkedHashMap<>();
            for (Map.Entry<?, ?> entry : ((Map<?, ?>) overridesObj).entrySet()) {
                if (!(entry.getKey() instanceof String) || !(entry.getValue() instanceof Map)) {
                    continue;
                }
                Map<?, ?> overrideRaw = (Map<?, ?>) entry.getValue();
                PromptOverride override = new PromptOverride();
                Object description = overrideRaw.get("description");
                if (description instanceof String) {
                    override.description = (String) description;
                }
                mergeStringMap(override.params, firstMap(overrideRaw.get("params"), overrideRaw.get("parameters")));
                Object resultObj = overrideRaw.get("result");
                if (resultObj instanceof Map) {
                    PromptResultOverride result = new PromptResultOverride();
                    Object resultDescription = ((Map<?, ?>) resultObj).get("description");
                    if (resultDescription instanceof String) {
                        result.description = (String) resultDescription;
                    }
                    mergeStringMap(
                        result.fields,
                        firstMap(((Map<?, ?>) resultObj).get("fields"), ((Map<?, ?>) resultObj).get("properties"))
                    );
                    if ((result.description != null && !result.description.isBlank()) || !result.fields.isEmpty()) {
                        override.result = result;
                    }
                }
                out.put((String) entry.getKey(), override);
            }
            log.info("Loaded tool prompt overrides from {} (tools={})", file, out.size());
            return out;
        } catch (Exception e) {
            log.warn("Failed to load tool prompt overrides from {}: {}", file, e.getMessage());
            return Collections.emptyMap();
        }
    }

    private Path resolvePromptFile() {
        String fromEnv = System.getenv(ENV_PROMPT_FILE);
        if (fromEnv != null && !fromEnv.isBlank()) {
            return toAbsolutePath(fromEnv.trim());
        }
        String fromProp = System.getProperty(SYS_PROP_PROMPT_FILE);
        if (fromProp != null && !fromProp.isBlank()) {
            return toAbsolutePath(fromProp.trim());
        }
        return toAbsolutePath(DEFAULT_PROMPT_FILE);
    }

    private Path toAbsolutePath(String raw) {
        Path path = Paths.get(raw);
        if (path.isAbsolute()) {
            return path.normalize();
        }
        return Paths.get(System.getProperty("user.dir")).resolve(path).normalize();
    }

    @SuppressWarnings("unchecked")
    private Map<?, ?> firstMap(Object primary, Object secondary) {
        if (primary instanceof Map) {
            return (Map<?, ?>) primary;
        }
        if (secondary instanceof Map) {
            return (Map<?, ?>) secondary;
        }
        return Collections.emptyMap();
    }

    private void mergeStringMap(Map<String, String> target, Map<?, ?> source) {
        if (source == null || source.isEmpty()) {
            return;
        }
        for (Map.Entry<?, ?> entry : source.entrySet()) {
            if (entry.getKey() instanceof String && entry.getValue() instanceof String) {
                target.put((String) entry.getKey(), (String) entry.getValue());
            }
        }
    }

    public static final class ToolSpec {
        private String name;
        private String description;
        private List<ToolParamSpec> parameters;
        private ToolResultSpec result;

        public ToolSpec(String name, String description, List<ToolParamSpec> parameters) {
            this(name, description, parameters, null);
        }

        public ToolSpec(String name, String description, List<ToolParamSpec> parameters, ToolResultSpec result) {
            this.name = name;
            this.description = description;
            this.parameters = parameters;
            this.result = result;
        }

        public String getName() {
            return name;
        }

        public void setName(String name) {
            this.name = name;
        }

        public String getDescription() {
            return description;
        }

        public void setDescription(String description) {
            this.description = description;
        }

