import com.fasterxml.jackson.databind.node.ObjectNode;
import lombok.RequiredArgsConstructor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@RequiredArgsConstructor
public class AiMcpEntryService {

    private static final Logger LOG = LoggerFactory.getLogger(AiMcpEntryService.class);
    private static final Logger INVOKE_LOG = LoggerFactory.getLogger("ai.tool.invoke");
    private static final int PREVIEW_MAX_CHARS = 512;

    private final AiProperties props;
    private final ToolRegistry toolRegistry;
    private final ObjectMapper objectMapper;
    private final AiMcpToolDispatcher toolDispatcher;

    /**
     * MCP tools/list 入口。
     * <p>
     * 约束：
     * 1) 先做 internal token 校验，避免暴露工具元信息给未授权调用方。
     * 2) 返回结构保持稳定，便于 Python 端缓存与对接。
     * </p>
     */
    public AiMcpToolsListResponse listTools(String token, AiMcpToolsListRequest req) {
        checkAccess(token);
        AiMcpToolsListRequest safeReq = req == null ? new AiMcpToolsListRequest() : req;
        // Reserved for future filtering:
        // - safeReq.scope
        AiMcpToolsListResponse resp = new AiMcpToolsListResponse();
        for (ToolRegistry.ToolSpec spec : toolRegistry.listToolSpecs()) {
            AiMcpToolDescriptor tool = new AiMcpToolDescriptor();
            tool.setName(spec.getName());
            tool.setDescription(spec.getDescription());
            JsonNode inputSchema = toInputSchemaNode(spec);
            tool.setInputSchema(inputSchema);
            // Backward compatibility for existing Python MCP client.
            tool.setParameters(inputSchema);
            JsonNode resultNode = toResultNode(spec);
            if (resultNode != null) {
                tool.setOutputSchema(resultNode);
                tool.setResult(resultNode);
            }
            resp.getTools().add(tool);
        }
        resp.setTotal(resp.getTools().size());
        return resp;
    }

    /**
     * MCP tools/call 入口。
     * <p>
     * 顺序固定为：
     * token 校验 -> caller 上下文校验 -> 业务调度。
     * 一旦前置校验失败，记录拒绝日志用于排障和审计。
     * </p>
     */
    public AiMcpToolsCallResponse callTool(String token, AiMcpToolsCallRequest req) {
        long startedAt = System.currentTimeMillis();

        try {
            checkAccess(token);
        } catch (AiMcpException e) {
            logDenied(req, "unauthorized", startedAt, e);
            throw e;
        }

        try {
            validateCallRequest(req);
        } catch (AiMcpException e) {
            logDenied(req, "authz_denied", startedAt, e);
            throw e;
        }
        return toolDispatcher.dispatch(req);
    }

    /**
     * 记录“请求被前置策略拒绝”的统一日志。
     * 这里记录的是拒绝事件，不是工具实际执行事件。
     */
    private void logDenied(AiMcpToolsCallRequest req, String status, long startedAt, AiMcpException e) {
        long latencyMs = System.currentTimeMillis() - startedAt;
        if (req == null) {
            logInvoke("-", "-", "-", null, null, null, status, latencyMs, e.getCode(), e.getMessage());
            return;
        }
        AiMcpCallerContext context = req.getContext();
        logInvoke(
            safe(req.getConversationId()),
            safe(req.getToolCallId()),
            safe(req.getToolName()),
            context == null ? null : context.getTenantId(),
            context == null ? null : context.getUserId(),
            req.getArgs(),
            status,
            latencyMs,
            e.getCode(),
            e.getMessage()
        );
    }

    /**
     * internal API 轻量鉴权。
     * 仅用于 Java<->Python 内部链路，不承担外部用户认证职责。
     */
    private void checkAccess(String providedToken) {
        AiProperties.Mcp mcp = props.getMcp();
        if (mcp == null || !mcp.isEnabled()) {
            throw new AiMcpException("mcp_disabled", "MCP internal API未启用", 403);
        }
        String internalToken = mcp.getInternalToken();
        if (internalToken == null || internalToken.isBlank()) {
            throw new AiMcpException("mcp_token_missing", "MCP internalToken未配置", 403);
        }
        if (!internalToken.equals(providedToken)) {
            throw new AiMcpException("mcp_unauthorized", "MCP internal token无效", 401);
        }
    }

    /**
     * tools/call 的最小上下文校验：
     * - context 必须存在
     * - tenantId / userId 必填
     */
    private void validateCallRequest(AiMcpToolsCallRequest req) {
        if (req == null) {
            throw new AiMcpException("mcp_bad_request", "request不能为空", 400);
        }
        AiMcpCallerContext context = req.getContext();
        if (context == null) {
            throw new AiMcpException("mcp_authz_invalid", "context不能为空", 400);
        }
        if (context.getTenantId() == null || context.getTenantId().isBlank()) {
            throw new AiMcpException("mcp_authz_invalid", "tenantId不能为空", 400);
        }
        try {
            Long.parseLong(context.getTenantId().trim());
        } catch (NumberFormatException e) {
            throw new AiMcpException("mcp_authz_invalid", "tenantId必须是数字", 400);
        }
        if (context.getUserId() == null) {
            throw new AiMcpException("mcp_authz_invalid", "userId不能为空", 400);
        }
    }

    /**
     * 将内部 ToolSpec 转换为 MCP 风格的 parameters(JSON Schema 子集)。
     * 保持输出结构稳定，避免前端/Agent SDK 解析抖动。
     */
    private JsonNode toInputSchemaNode(ToolRegistry.ToolSpec definition) {
        ObjectNode node = objectMapper.createObjectNode();
        if (definition == null) {
            return node;
        }
        node.put("type", "object");
        ObjectNode properties = objectMapper.createObjectNode();
        ArrayNode required = objectMapper.createArrayNode();
        for (ToolRegistry.ToolParamSpec param : definition.getParameters()) {
            ObjectNode property = objectMapper.createObjectNode();
            property.put("type", param.getType() == null || param.getType().isBlank() ? "string" : param.getType());
            if (param.getDescription() != null && !param.getDescription().isBlank()) {
                property.put("description", param.getDescription());
            }
            appendSemanticHints(property, param.getSemanticHints());
            properties.set(param.getName(), property);
            if (param.isRequired()) {
                required.add(param.getName());
            }
        }
        node.set("properties", properties);
        node.set("required", required);
        // Reject unknown args by default to match strict tool validation.
        node.put("additionalProperties", false);
        return node;
    }

    private JsonNode toResultNode(ToolRegistry.ToolSpec definition) {
        if (definition == null || definition.getResult() == null) {
            return null;
        }
        ToolRegistry.ToolResultSpec resultSpec = definition.getResult();
        boolean hasDescription = resultSpec.getDescription() != null && !resultSpec.getDescription().isBlank();
        boolean hasFields = resultSpec.getFields() != null && !resultSpec.getFields().isEmpty();
        if (!hasDescription && !hasFields) {
            return null;
        }
        ObjectNode node = objectMapper.createObjectNode();
        node.put("type", "object");
        if (hasDescription) {
            node.put("description", resultSpec.getDescription());
        }
        ObjectNode properties = objectMapper.createObjectNode();
        if (hasFields) {
            for (java.util.Map.Entry<String, String> entry : resultSpec.getFields().entrySet()) {
                if (entry.getKey() == null || entry.getKey().isBlank()) {
                    continue;
                }
                ObjectNode property = objectMapper.createObjectNode();
                if (entry.getValue() != null && !entry.getValue().isBlank()) {
                    property.put("description", entry.getValue());
                }
                properties.set(entry.getKey(), property);
            }
        }
        node.set("properties", properties);

