    }

    private void appendSemanticHints(ObjectNode property, java.util.Map<String, Object> semanticHints) {
        if (semanticHints == null || semanticHints.isEmpty()) {
            return;
        }
        for (java.util.Map.Entry<String, Object> entry : semanticHints.entrySet()) {
            String key = entry.getKey();
            Object value = entry.getValue();
            if (key == null || key.isBlank() || value == null) {
                continue;
            }
            property.set(key, objectMapper.valueToTree(value));
        }
    }

    private void logInvoke(String conversationId,
                           String toolCallId,
                           String toolName,
                           String tenantId,
                           Long userId,
                           JsonNode args,
                           String status,
                           long latencyMs,
                           String errorCode,
                           String resultPreview) {
        INVOKE_LOG.info(
            "conversationId={} toolCallId={} toolName={} tenant={} user={} status={} latency={} errorCode={} argsPreview={} resultPreview={}",
            safe(conversationId),
            safe(toolCallId),
            safe(toolName),
            safe(tenantId),
            userId == null ? "-" : userId,
            safe(status),
            latencyMs,
            safe(errorCode),
            previewJson(args),
            previewText(resultPreview)
        );
    }

    private String previewJson(JsonNode node) {
        if (node == null || node.isNull()) {
            return "";
        }
        return previewText(node.toString());
    }

    private String previewText(String text) {
        if (text == null || text.isBlank()) {
            return "";
        }
        String oneLine = text.replace('\n', ' ').replace('\r', ' ').replace('\t', ' ');
        if (oneLine.length() <= PREVIEW_MAX_CHARS) {
            return oneLine;
        }
        return oneLine.substring(0, PREVIEW_MAX_CHARS) + "...";
    }

    private String safe(String value) {
        if (value == null || value.isBlank()) {
            return "-";
        }
        return value;
    }
}

